class Solution:
    def checkRecord(self, n):
        MOD = 10**9 + 7
        from collections import defaultdict
        dp = {(0, 0): 1}
        for _ in range(n):
            ndp = defaultdict(int)
            for (a, l), c in dp.items():
                ndp[(a, 0)] = (ndp[(a, 0)] + c) % MOD
                if a < 1:
                    ndp[(a + 1, 0)] = (ndp[(a + 1, 0)] + c) % MOD
                if l < 2:
                    ndp[(a, l + 1)] = (ndp[(a, l + 1)] + c) % MOD
            dp = ndp
        return sum(dp.values()) % MOD

