class Solution:
    def checkRecord(self, n):
        MOD = 10 ** 9 + 7
        states = [[0, 0, 0], [0, 0, 0]]
        states[0][0] = 1
        for _ in range(n):
            nxt = [[0, 0, 0], [0, 0, 0]]
            for a in range(2):
                for l in range(3):
                    cur = states[a][l]
                    if cur == 0:
                        continue
                    nxt[a][0] = (nxt[a][0] + cur) % MOD
                    if a == 0:
                        nxt[1][0] = (nxt[1][0] + cur) % MOD
                    if l < 2:
                        nxt[a][l + 1] = (nxt[a][l + 1] + cur) % MOD
            states = nxt
        total = 0
        for a in range(2):
            for l in range(3):
                total = (total + states[a][l]) % MOD
        return total

