var checkRecord = function(n) {
    const MOD = 1000000007n;
    let states = [[1n, 0n, 0n], [0n, 0n, 0n]];
    for (let i = 0; i < n; i++) {
        const nxt = [[0n, 0n, 0n], [0n, 0n, 0n]];
        for (let a = 0; a < 2; a++) {
            for (let l = 0; l < 3; l++) {
                const cur = states[a][l];
                if (cur === 0n) continue;
                nxt[a][0] = (nxt[a][0] + cur) % MOD;
                if (a === 0) nxt[1][0] = (nxt[1][0] + cur) % MOD;
                if (l < 2) nxt[a][l + 1] = (nxt[a][l + 1] + cur) % MOD;
            }
        }
        states = nxt;
    }
    let total = 0n;
    for (let a = 0; a < 2; a++) {
        for (let l = 0; l < 3; l++) {
            total = (total + states[a][l]) % MOD;
        }
    }
    return Number(total);
};
